    21→// Get candidate profile
    22→router.get('/profile', authMiddleware, async (req, res) => {
    23→  try {
    24→    const profile = await pool.query(`
    25→      SELECT cp.*, u.name, u.email, u.avatar_url, u.github_username
    26→      FROM users u
    27→      LEFT JOIN candidate_profiles cp ON cp.user_id = u.id
    28→      WHERE u.id = $1
    29→    `, [req.user.id]);
    30→
    31→    const experience = await pool.query(
    32→      'SELECT * FROM work_experience WHERE user_id = $1 ORDER BY order_index, start_date DESC',
    33→      [req.user.id]
    34→    );
    35→
    36→    const education = await pool.query(
    37→      'SELECT * FROM education WHERE user_id = $1 ORDER BY order_index, start_date DESC',
    38→      [req.user.id]
    39→    );
    40→
    41→    const skills = await pool.query(
    42→      'SELECT * FROM candidate_skills WHERE user_id = $1 ORDER BY level DESC, skill_name',
    43→      [req.user.id]
    44→    );
    45→
    46→    const projects = await pool.query(
    47→      'SELECT * FROM portfolio_projects WHERE user_id = $1 ORDER BY order_index, start_date DESC',
    48→      [req.user.id]
    49→    );
    50→
    51→    res.json({
    52→      success: true,
    53→      profile: profile.rows[0] || {},
