   257→// Apply parsed resume data to profile
   258→router.post('/resume/apply', authMiddleware, async (req, res) => {
   259→  try {
   260→    const { parsed_data, apply_sections } = req.body;
   261→
   262→    if (!parsed_data) {
   263→      return res.status(400).json({ error: 'No parsed data provided' });
   264→    }
   265→
   266→    const sections = apply_sections || ['profile', 'experience', 'education', 'skills'];
   267→
   268→    // Apply profile info
   269→    if (sections.includes('profile') && parsed_data.contact) {
   270→      await pool.query(`
   271→        INSERT INTO candidate_profiles (user_id, headline, bio, location, linkedin_url, github_url, portfolio_url, years_experience)
   272→        VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
   273→        ON CONFLICT (user_id) DO UPDATE SET
