   314→          exp.is_current || exp.end_date === 'Present',
   315→          exp.description,
   316→          JSON.stringify(exp.achievements || []),
   317→          JSON.stringify(exp.skills_used || []),
   318→          i
   319→        ]);
   320→      }
   321→    }
   322→
   323→    // Apply education
   324→    if (sections.includes('education') && parsed_data.education) {
   325→      for (let i = 0; i < parsed_data.education.length; i++) {
